examples.query:
mutation TestJWT {
  testPlaybackAccess(input: {
    playbackId: "<playback-id>"
    viewerToken: "eyJhbGciOiJFUzI1NiIs..."
    connector: "hls"
  }) {
    ... on PlaybackAccessDecision {
      allowed
      reason
      kid
      claimsJson
    }
    ... on ValidationError { message field }
  }
}

mutation Inspect {
  testPlaybackAccess(input: {
    playbackId: "<playback-id>"
    fireWebhook: false
  }) {
    ... on PlaybackAccessDecision { policyType reason detail }
  }
}

mutation Fire {
  testPlaybackAccess(input: {
    playbackId: "<playback-id>"
    viewerIp: "203.0.113.42"
    connector: "hls"
    fireWebhook: true
  }) {
    ... on PlaybackAccessDecision {
      allowed reason webhookStatus webhookLatencyMs
    }
  }
}

query MediaRetentionPolicy {
  mediaRetentionPolicy {
    defaultVodRetentionDays
    defaultDvrRetentionDays
    defaultClipRetentionDays
    effectiveVodRetentionDays
    effectiveDvrRetentionDays
    effectiveClipRetentionDays
    bounds { maxRecordingRetentionDays }
  }
}

mutation Set { setMediaRetentionPolicy(input: { targetType: VOD, days: 0 }) {
  ... on MediaRetentionPolicy { effectiveVodRetentionDays }
  ... on ValidationError { message field }
} }

mutation Set { setMediaRetentionPolicy(input: { targetType: CLIP, days: 14 }) {
  ... on MediaRetentionPolicy { effectiveClipRetentionDays }
  ... on ValidationError { message field }
} }

mutation Override {
  setStreamRetentionOverrides(input: {
    streamId: "<stream-id>",
    dvrRetentionDaysOverride: 90,
    clearClipRetentionOverride: true
  }) {
    ... on StreamRetentionOverrides { dvrRetentionDaysOverride clipRetentionDaysOverride }
    ... on ValidationError { message field }
  }
}

mutation Update {
  updateMediaRetention(input: { targetType: CLIP, targetId: "<clip-hash>", retentionDays: 0 }) {
    ... on EffectiveRetention { retentionDays retentionUntil source }
    ... on ValidationError { message field }
  }
}

query PreviewAssets($contentId: String!) {
  resolveViewerEndpoint(contentId: $contentId) {
    metadata {
      thumbnailAssets {
        posterUrl
        spriteVttUrl
        spriteJpgUrl
        assetKey
      }
    }
  }
}

mutation Drain { setNodeMode(input: { nodeId: "<node-id>", mode: DRAINING, reason: "monthly maintenance" }) {
  ... on InfrastructureNode {
    nodeId
    effectiveMode
    routingImpactPreview { activeStreams activeViewers }
  }
  ... on ValidationError { message field }
  ... on NotFoundError { message }
} }

mutation Restore { setNodeMode(input: { nodeId: "<node-id>", mode: NORMAL }) {
  ... on InfrastructureNode { effectiveMode }
  ... on ValidationError { message field }
} }
